#include <stdio.h>
int main(){
    int T;
    scanf("%d", &T);
    while(T--){
        long long L, R;
        scanf("%lld %lld", &L, &R);
        long long e = (L % 2 == 0) ? L : L + 1;
        if(e + 3 <= R)
            printf("%lld %lld %lld %lld\n", e, e + 1, e + 2, e + 3);
        else
            printf("-1\n");
    }
    return 0;
}

